// jsDelivr 的 Typst compiler/renderer +esm 需要显式 WASM importer；渲染器返回含脚本的 SVG HTML fragment,不可按 XML 重解析
import { $typst } from 'https://cdn.jsdelivr.net/npm/@myriaddreamin/typst.ts@0.7.0/+esm';
import * as compilerWasm from 'https://cdn.jsdelivr.net/npm/@myriaddreamin/typst-ts-web-compiler@0.7.0/+esm';
import * as rendererWasm from 'https://cdn.jsdelivr.net/npm/@myriaddreamin/typst-ts-renderer@0.7.0/+esm';
const fetchWasm = (name, url) => fetch(new URL(name, url)); compilerWasm.setImportWasmModule(fetchWasm); rendererWasm.setImportWasmModule(fetchWasm);
const el = document.getElementById('typst'); el.style.cssText = 'height:640px;overflow:auto'; el.textContent = 'Compiling Typst…';
const svg = await $typst.svg({ mainContent:data.mainContent, inputs:data.inputs ?? {} });
el.innerHTML = svg;

